//
// Component: Info Box
//

.info-box {
  @include box-shadow($lte-card-shadow);
  @include border-radius($border-radius);

  position: relative;
  display: flex;
  width: 100%;
  min-height: 80px;
  padding: .5rem;
  margin-bottom: map-get($spacers, 3);
  color: var(--#{$prefix}body-color);
  background-color: var(--#{$prefix}body-bg);

  .progress {
    height: 2px;
    margin: 5px 0;
    background-color: rgba(var(--#{$lte-prefix}card-variant-color-rgb), .125);

    .progress-bar {
      background-color: var(--#{$lte-prefix}card-variant-color);
    }
  }

  .info-box-icon {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 70px;
    font-size: 1.875rem;
    text-align: center;
    @include border-radius($border-radius);

    > img {
      max-width: 100%;
    }
  }

  .info-box-content {
    display: flex;
    flex: 1;
    flex-direction: column;
    justify-content: center;
    padding: 0 10px;
    line-height: 1.8;
  }

  .info-box-number {
    display: block;
    margin-top: .25rem;
    font-weight: $font-weight-bold;
  }

  .progress-description,
  .info-box-text {
    display: block;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .info-box-more {
    display: block;
  }

  .progress-description {
    margin: 0;

  }

  @include media-breakpoint-up(md) {
    .col-xl-2 &,
    .col-lg-2 &,
    .col-md-2 & {
      .progress-description {
        display: none;
      }
    }

    .col-xl-3 &,
    .col-lg-3 &,
    .col-md-3 & {
      .progress-description {
        display: none;
      }
    }
  }

  @include media-breakpoint-up(lg) {
    .col-xl-2 &,
    .col-lg-2 &,
    .col-md-2 & {
      .progress-description {
        @include font-size(.75rem);
        display: block;
      }
    }

    .col-xl-3 &,
    .col-lg-3 &,
    .col-md-3 & {
      .progress-description {
        @include font-size(.75rem);
        display: block;
      }
    }
  }

  @include media-breakpoint-up(xl) {
    .col-xl-2 &,
    .col-lg-2 &,
    .col-md-2 & {
      .progress-description {
        @include font-size(1rem);
        display: block;
      }
    }

    .col-xl-3 &,
    .col-lg-3 &,
    .col-md-3 & {
      .progress-description {
        @include font-size(1rem);
        display: block;
      }
    }
  }
}

//
// Component: Small Box
//

.small-box {
  @include border-radius($border-radius);
  @include box-shadow($lte-card-shadow);
  position: relative;
  display: block;
  margin-bottom: 1.25rem;
  --bs-link-color-rgb: none;
  --bs-link-hover-color-rgb: none;
  --bs-heading-color: none;

  // content wrapper
  > .inner {
    padding: 10px;
  }

  > .small-box-footer {
    position: relative;
    z-index: 10;
    display: block;
    padding: 3px 0;
    text-align: center;
    background-color: rgba($black, .07);

    &:hover {
      background-color: rgba($black, .1);
    }
  }

  h3 {
    @include font-size(2.2rem);
    padding: 0;
    margin: 0 0 10px;
    font-weight: 700;
    white-space: nowrap;
  }

  @include media-breakpoint-up(lg) {
    .col-xl-2 &,
    .col-lg-2 &,
    .col-md-2 & {
      h3 {
        @include font-size(1.6rem);
      }
    }

    .col-xl-3 &,
    .col-lg-3 &,
    .col-md-3 & {
      h3 {
        @include font-size(1.6rem);
      }
    }
  }

  @include media-breakpoint-up(xl) {
    .col-xl-2 &,
    .col-lg-2 &,
    .col-md-2 & {
      h3 {
        @include font-size(2.2rem);
      }
    }

    .col-xl-3 &,
    .col-lg-3 &,
    .col-md-3 & {
      h3 {
        @include font-size(2.2rem);
      }
    }
  }

  p {
    font-size: 1rem;

    > small {
      display: block;
      margin-top: 5px;
      font-size: .9rem;
      color: $gray-100;
    }
  }

  h3,
  p {
    z-index: 5;
  }

  // the icon
  .small-box-icon {
    position: absolute;
    top: 15px;
    right: 15px;
    z-index: 0;
    height: 70px;
    font-size: 70px;
    color: rgba($black, .15);
    @include transition(transform $lte-transition-speed linear);
  }

  // Small box hover state
  &:hover {
    // Animate icons on small box hover
    .small-box-icon {
      transform: scale(1.1);
    }
  }
}

@include media-breakpoint-down(sm) {
  // No need for icons on very small devices
  .small-box {
    text-align: center;

    .small-box-icon {
      display: none;
    }

    p {
      font-size: 12px;
    }
  }
}

$pricing-card-width: 22rem;

.pricing {
  display: flex;
  flex-direction: column;
  margin: 0 auto;
  justify-content: center;

  @include media-breakpoint-up(md) {
    flex-direction: row;
  }
}

.pricing-card {
  flex: 1;
  display: flex;
  flex-direction: column;
  background: var(--#{$prefix}bg-surface);
  border: 1px solid $border-color;
  padding: 2rem;
  margin: 0 0 1rem;
  position: relative;
  box-shadow: var(--#{$prefix}shadow-card);
  text-align: center;
  @include border-radius($border-radius-lg);

  @include media-breakpoint-up(md) {
    margin: 1rem -1px;
    max-width: $pricing-card-width;

    &:first-child {
      @include border-radius($border-radius-lg 0 0 $border-radius-lg);
    }

    &:last-child {
      @include border-radius(0 $border-radius-lg $border-radius-lg 0);
    }
  }

  &.featured {
    z-index: 1;
    border: 2px solid var(--#{$prefix}primary);
    order: -1;

    @include media-breakpoint-up(md) {
      order: unset;
      margin-top: 0;
      margin-bottom: 0;
      box-shadow: var(--#{$prefix}shadow-card);
      @include border-radius($border-radius-lg);
    }
  }
}

.pricing-title {
  font-size: $h2-font-size;
  line-height: $h2-line-height;
}

.pricing-label {
  position: absolute;
  top: 0;
  inset-inline-start: 0;
  transform: translateY(-50%);
  vertical-align: bottom;
  inset-inline-end: 0;
  display: flex;
  align-items: center;
  justify-content: center;
}

.pricing-btn {
  margin-top: auto;
  padding-top: 2rem;
}

.pricing-price {
  display: flex;
  justify-content: center;
  font-size: 2.5rem;
  line-height: 1;
  font-weight: $font-weight-semibold;
  margin: 0.75rem 0;
}

.pricing-price-currency {
  font-size: $h2-font-size;
  line-height: 1.5;
  margin-inline-end: 0.25rem;
  font-weight: $font-weight-semibold;
}

.pricing-price-description {
  font-size: $h4-font-size;
  line-height: $h4-line-height;
  font-weight: $font-weight-normal;
  color: $text-secondary;
  align-self: center;
  margin-inline-start: 0.5rem;
}

.pricing-features {
  margin: 1rem 0 0;
  padding: 0;
  list-style: none;
  text-align: start;

  > li:not(:first-child) {
    margin-top: 0.25rem;
  }
}

//
// Rotating border
//

.spinner-grow,
.spinner-border {
  display: inline-block;
  flex-shrink: 0;
  width: var(--#{$prefix}spinner-width);
  height: var(--#{$prefix}spinner-height);
  vertical-align: var(--#{$prefix}spinner-vertical-align);
  // stylelint-disable-next-line property-disallowed-list
  border-radius: 50%;
  animation: var(--#{$prefix}spinner-animation-speed) linear infinite var(--#{$prefix}spinner-animation-name);
}

// scss-docs-start spinner-border-keyframes
@keyframes spinner-border {
  to { transform: rotate(360deg) #{"/* rtl:ignore */"}; }
}
// scss-docs-end spinner-border-keyframes

.spinner-border {
  // scss-docs-start spinner-border-css-vars
  --#{$prefix}spinner-width: #{$spinner-width};
  --#{$prefix}spinner-height: #{$spinner-height};
  --#{$prefix}spinner-vertical-align: #{$spinner-vertical-align};
  --#{$prefix}spinner-border-width: #{$spinner-border-width};
  --#{$prefix}spinner-animation-speed: #{$spinner-animation-speed};
  --#{$prefix}spinner-animation-name: spinner-border;
  // scss-docs-end spinner-border-css-vars

  border: var(--#{$prefix}spinner-border-width) solid currentcolor;
  border-right-color: transparent;
}

.spinner-border-sm {
  // scss-docs-start spinner-border-sm-css-vars
  --#{$prefix}spinner-width: #{$spinner-width-sm};
  --#{$prefix}spinner-height: #{$spinner-height-sm};
  --#{$prefix}spinner-border-width: #{$spinner-border-width-sm};
  // scss-docs-end spinner-border-sm-css-vars
}

//
// Growing circle
//

// scss-docs-start spinner-grow-keyframes
@keyframes spinner-grow {
  0% {
    transform: scale(0);
  }
  50% {
    opacity: 1;
    transform: none;
  }
}
// scss-docs-end spinner-grow-keyframes

.spinner-grow {
  // scss-docs-start spinner-grow-css-vars
  --#{$prefix}spinner-width: #{$spinner-width};
  --#{$prefix}spinner-height: #{$spinner-height};
  --#{$prefix}spinner-vertical-align: #{$spinner-vertical-align};
  --#{$prefix}spinner-animation-speed: #{$spinner-animation-speed};
  --#{$prefix}spinner-animation-name: spinner-grow;
  // scss-docs-end spinner-grow-css-vars

  background-color: currentcolor;
  opacity: 0;
}

.spinner-grow-sm {
  --#{$prefix}spinner-width: #{$spinner-width-sm};
  --#{$prefix}spinner-height: #{$spinner-height-sm};
}

@if $enable-reduced-motion {
  @media (prefers-reduced-motion: reduce) {
    .spinner-border,
    .spinner-grow {
      --#{$prefix}spinner-animation-speed: #{$spinner-animation-speed * 2};
    }
  }
}

@use "sass:color";

.welcome-accordion {
  margin-top: 3rem;
  margin-bottom: 3rem;
}

.welcome-accordion-item {

  &.is-active {
    // box-shadow: 0px 1px 8px 0px rgba(0,0,0,0.15);

    .accordion-title {
      margin-bottom: 0;
      border-bottom: none;
      color: $black;
      border: none;
      padding-left: 1rem;
    }

    .accordion-content {
      // margin-bottom: 1rem;
      border: none;
      border-bottom: 1px dashed #e6e6e6;
    }
  }

  .accordion-title:focus,
  .accordion-title:active {
    background: none;
  }

  .accordion-title {
    color: color.adjust($dark-gray, $lightness: -10%);
    font-size: 1.25rem;
    line-height: 1.5;
    padding-left: 0;
    background: none;
    border: none;
    border-bottom: 1px dashed #d6d6d6;
    transition: all 0.3s ease;
  }

  .accordion-title:hover {
    padding-left: 1rem;
    color: $black;
    transition: all 0.3s ease;
  }

  .accordion-title::before {
    color: $dark-gray;
    font-size: 1.25rem;
    line-height: 1;
    top: 45%;
    border-radius: 50%;
    border: 1px solid $light-gray;
    background-color: $white;
    width: 25px;
    height: 25px;
    text-align: center;
    transition: all 0.3s ease;
  }

  .accordion-title:hover::before {
    color: $black;
    background-color: color.adjust($light-gray, $lightness: 8%);
    border: 1px solid $medium-gray;
    transition: all 0.3s ease;
  }
}

.welcome-accordion-item:last-child {

  .accordion-title{
    border-bottom: none;
  }
}

.accordion-content-item {
  font-family: Helvetica, Arial, sans-serif;
  margin-bottom: 2rem;
}

.docs-component .accordion-content-item-divider {
  border-bottom: 1px dashed #e5e5e5;
  margin-bottom: 0;
}

.accordion-content-item-thumbnail {

  img {
    border: 1px solid $light-gray;
  }

  @include breakpoint(small down) {
    margin-bottom: 1rem;
  }
}

.accordion-content-item-cta {

  img {
    margin-right: 0.5rem;
  }
}

// Prevent FOUC on nav accordion
.accordion-content.is-active {
  display: block;
}

.responsive-embed {
  margin-bottom: 0;
}

@use "sass:color";

// Grid
.row.display {
  background: #eee;
  font-size: 11px;
  margin-bottom: 10px;
  line-height: 2rem;
  border: solid 1px #c6c6c6;
  margin-left: 0 !important;
  margin-right: 0 !important;

  .columns {
    &:nth-child(2),
    &.small-centered,
    &.large-centered {
      background: color.adjust(#eee, $lightness: -5%);
    }

    &.color-end {
      background: color.adjust(#eee, $lightness: -10%)
    }
  }
}

.row.display-end {
  background: #fff;
  font-size: 11px;
  margin-bottom: 10px;
  line-height: 2rem;
  border: solid 1px #c6c6c6;
  margin-left: 0 !important;
  margin-right: 0 !important;

  .columns {
    background: color.adjust(#eee, $lightness: -5%);
    border-left: 1px solid #c6c6c6;

    &.color-end {
      background: color.adjust(#eee, $lightness: -10%)
    }
  }
}

// Flex Grid
[id^="docs-flex"].docs-component .docs-code-live {
  @include foundation-flex-grid;

  .row {
    background: #f9f9f9;
    font-size: 11px;
    line-height: 2rem;
    border: solid 1px #c6c6c6;
    margin-left: 0;
    margin-right: 0;
    margin-bottom: 1.5rem;

    // Disable clearfix
    &::before,
    &::after {
      display: none;
    }
  }

  .column,
  .columns {
    float: none;
    width: auto;

    &:nth-child(odd) {
      background: #eee;
    }
    &:nth-child(even) {
      background: #ddd;
    }
  }
}

// XY Grid & Flexbox Utilities
[id^="docs-xy"].docs-component .docs-code-live,
[id^="docs-flexbox-utilities"].docs-component .docs-code-live {
  @include foundation-flex-grid;
  @include foundation-xy-grid-classes;

  .grid-x,
  .grid-y {
    background: color.adjust($primary-color, $lightness: 50%);
    font-size: 12px;
    line-height: 2rem;
    margin-bottom: 1.5rem;
  }

  .grid-y .grid-x {
    margin-bottom: 0;
  }

  .cell {
    &:nth-child(odd) {
      background: color.adjust($primary-color, $lightness: 30%);
      color: $black;
    }
    &:nth-child(even) {
      background: $primary-color;
      color: $white;
    }
  }
}

$button-responsive-expanded: true;

@import "./picker";
@import "./picker.ios.vars";

// iOS Picker
// --------------------------------------------------

:host {
  --background: #{$picker-ios-background-color};
  --border-width: #{1px 0 0};
  --border-color: #{$picker-ios-border-color};
  --height: #{$picker-ios-height};
  --backdrop-opacity: var(--ion-backdrop-opacity, 0.26);

  color: $picker-ios-option-text-color;
}

.picker-toolbar {
  display: flex;

  height: $picker-ios-toolbar-height;

  border-bottom: $hairlines-width solid var(--border-color);
}

.picker-toolbar-button {
  flex: 1;

  text-align: end;
}

.picker-toolbar-button:last-child .picker-button {
  font-weight: $picker-ios-button-strong-font-weight;
}

.picker-toolbar-button:first-child {
  font-weight: normal;

  text-align: start;
}

.picker-button,
.picker-button.ion-activated {
  @include margin(0);
  @include padding($picker-ios-button-padding-top, $picker-ios-button-padding-end, $picker-ios-button-padding-bottom, $picker-ios-button-padding-start);

  height: $picker-ios-button-height;

  background: transparent;
  color: $picker-ios-button-text-color;

  font-size: $picker-ios-button-font-size;
}

.picker-columns {
  height: $picker-ios-height - $picker-ios-toolbar-height - 1;
  perspective: $picker-ios-column-perspective;
}

.picker-above-highlight {
  @include position(0, null, null, 0);
  @include transform(translate3d(0, 0, 90px));

  display: block;
  position: absolute;

  width: 100%;
  height: $picker-ios-option-offset-y + 4px;

  border-bottom: 1px solid var(--border-color);

  background: linear-gradient(
    to bottom,
    $picker-ios-top-background-color 20%,
    $picker-ios-bottom-background-color 100%);

  z-index: 10;
}

.picker-below-highlight {
  @include position($picker-ios-option-offset-y + $picker-ios-option-height - 4, null, null, 0);
  @include transform(translate3d(0, 0, 90px));

  display: block;
  position: absolute;

  width: 100%;
  height: $picker-ios-option-offset-y + $picker-ios-option-height;

  border-top: 1px solid var(--border-color);

  background: linear-gradient(
    to top,
    $picker-ios-top-background-color 30%,
    $picker-ios-bottom-background-color 100%);

  z-index: 11;
}

// Image comparison slider
// Credit: http://codepen.io/solipsistacp/pen/Gpmaq
.comparison-slider {
  height: 50vh;
  overflow: hidden;
  position: relative;
  width: 100%;
  -webkit-overflow-scrolling: touch;

  .comparison-before,
  .comparison-after {
    height: 100%;
    left: 0;
    margin: 0;
    overflow: hidden;
    position: absolute;
    top: 0;

    img {
      height: 100%;
      object-fit: cover;
      object-position: left center;
      position: absolute;
      width: 100%;
    }
  }

  .comparison-before {
    width: 100%;
    z-index: 1;

    .comparison-label {
      right: $unit-4;
    }
  }

  .comparison-after {
    max-width: 100%;
    min-width: 0;
    z-index: 2;

    &::before {
      background: transparent;
      content: "";
      cursor: default;
      height: 100%;
      left: 0;
      position: absolute;
      right: $unit-4;
      top: 0;
      z-index: $zindex-0;
    }

    &::after {
      background: currentColor;
      border-radius: 50%;
      box-shadow: 0 -5px, 0 5px;
      color: $light-color;
      content: "";
      height: 3px;
      pointer-events: none;
      position: absolute;
      right: $unit-2;
      top: 50%;
      transform: translate(50%, -50%);
      width: 3px;
    }

    .comparison-label {
      left: $unit-4;
    }
  }

  .comparison-resizer {
    animation: first-run 1.5s 1 ease-in-out;
    cursor: ew-resize;
    height: $unit-4;
    left: 0;
    max-width: 100%;
    min-width: $unit-4;
    opacity: 0;
    outline: none;
    position: relative;
    resize: horizontal;
    top: 50%;
    transform: translateY(-50%) scaleY(30);
    width: 0;
  }

  .comparison-label {
    background: rgba($dark-color, .5);
    bottom: $unit-4;
    color: $light-color;
    padding: $unit-1 $unit-2;
    position: absolute;
    user-select: none;
  }
}

@keyframes first-run {
  0% {
    width: 0;
  }
  25% {
    width: $unit-12;
  }
  50% {
    width: $unit-4;
  }
  75% {
    width: $unit-6;
  }
  100% {
    width: 0;
  }
}

// Needs refactoring
// stylelint-disable selector-max-specificity
// stylelint-disable selector-max-type
.markdown-body {
  // Headings
  h1,
  h2,
  h3,
  h4,
  h5,
  h6 {
    margin-top: var(--base-size-24);
    margin-bottom: var(--base-size-16);
    // stylelint-disable-next-line primer/typography
    font-weight: $font-weight-bold;
    // stylelint-disable-next-line primer/typography
    line-height: $lh-condensed;

    .octicon-link {
      color: var(--fgColor-default, var(--color-fg-default));
      vertical-align: middle;
      visibility: hidden;
    }

    &:hover .anchor {
      text-decoration: none;

      .octicon-link {
        visibility: visible;
      }
    }

    tt,
    code {
      // stylelint-disable-next-line primer/spacing
      padding: 0 0.2em;
      font-size: inherit;
    }
  }

  h1 {
    // stylelint-disable-next-line primer/spacing
    padding-bottom: 0.3em;
    // stylelint-disable-next-line primer/typography
    font-size: 2em;
    // stylelint-disable-next-line primer/borders, primer/colors
    border-bottom: $border-width $border-style var(--borderColor-muted, var(--color-border-muted));
  }

  h2 {
    // stylelint-disable-next-line primer/spacing
    padding-bottom: 0.3em;
    // stylelint-disable-next-line primer/typography
    font-size: 1.5em;
    // stylelint-disable-next-line primer/borders, primer/colors
    border-bottom: $border-width $border-style var(--borderColor-muted, var(--color-border-muted));
  }

  h3 {
    // stylelint-disable-next-line primer/typography
    font-size: 1.25em;
  }

  h4 {
    // stylelint-disable-next-line primer/typography
    font-size: 1em;
  }

  h5 {
    // stylelint-disable-next-line primer/typography
    font-size: 0.875em;
  }

  h6 {
    // stylelint-disable-next-line primer/typography
    font-size: 0.85em;
    color: var(--fgColor-muted, var(--color-fg-muted));
  }

  summary {
    h1,
    h2,
    h3,
    h4,
    h5,
    h6 {
      display: inline-block;

      .anchor {
        // stylelint-disable-next-line primer/spacing
        margin-left: -40px;
      }
    }

    h1,
    h2 {
      padding-bottom: 0;
      border-bottom: 0;
    }
  }
}

// stylelint-disable selector-max-specificity

// Filters list
//
// A vertical list of filters.
.filter-list {
  list-style-type: none;

  &.small .filter-item {
    // stylelint-disable-next-line primer/spacing
    padding: 6px 12px;
    // stylelint-disable-next-line primer/typography
    font-size: $font-size-small;
  }

  &.pjax-active .filter-item {
    color: var(--fgColor-muted, var(--color-fg-muted));
    background-color: transparent;

    &.pjax-active {
      color: var(--fgColor-onEmphasis, var(--color-fg-on-emphasis));
      background-color: var(--bgColor-accent-emphasis, var(--color-accent-emphasis));
    }
  }
}

.filter-item {
  position: relative;
  display: block;
  padding: var(--base-size-8) var(--base-size-16);
  margin-bottom: var(--base-size-4);
  overflow: hidden;
  // stylelint-disable-next-line primer/typography
  font-size: $h5-size;
  color: var(--fgColor-muted, var(--color-fg-muted));
  text-decoration: none;
  text-overflow: ellipsis;
  white-space: nowrap;
  cursor: pointer;
  // stylelint-disable-next-line primer/borders
  border-radius: $border-radius;

  &:hover {
    text-decoration: none;
    background-color: var(--bgColor-muted, var(--color-canvas-subtle));
  }

  &.selected,
  &[aria-selected='true'],
  &[aria-current]:not([aria-current='false']) {
    color: var(--fgColor-onEmphasis, var(--color-fg-on-emphasis));
    background-color: var(--bgColor-accent-emphasis, var(--color-accent-emphasis));

    // fallback :focus state
    &:focus {
      @include focusOutlineOnEmphasis;

      // remove fallback :focus if :focus-visible is supported
      &:not(:focus-visible) {
        outline: solid 1px transparent;
        box-shadow: none;
      }
    }

    // default focus state
    &:focus-visible {
      @include focusOutlineOnEmphasis;
    }
  }

  .count {
    float: right;
    // stylelint-disable-next-line primer/typography
    font-weight: $font-weight-bold;
  }

  .bar {
    position: absolute;
    top: var(--base-size-2);
    right: 0;
    bottom: var(--base-size-2);
    z-index: -1;
    display: inline-block;
    background-color: var(--bgColor-neutral-muted, var(--color-neutral-subtle));
  }
}

//
// Progress bars
// --------------------------------------------------


// Bar animations
// -------------------------

// WebKit
@-webkit-keyframes progress-bar-stripes {
  from  { background-position: 40px 0; }
  to    { background-position: 0 0; }
}

// Spec and IE10+
@keyframes progress-bar-stripes {
  from  { background-position: 40px 0; }
  to    { background-position: 0 0; }
}


// Bar itself
// -------------------------

// Outer container
.progress {
  height: $line-height-computed;
  margin-bottom: $line-height-computed;
  overflow: hidden;
  background-color: $progress-bg;
  border-radius: $progress-border-radius;
  @include box-shadow(inset 0 1px 2px rgba(0, 0, 0, .1));
}

// Bar of progress
.progress-bar {
  float: left;
  width: 0%;
  height: 100%;
  font-size: $font-size-small;
  line-height: $line-height-computed;
  color: $progress-bar-color;
  text-align: center;
  background-color: $progress-bar-bg;
  @include box-shadow(inset 0 -1px 0 rgba(0, 0, 0, .15));
  @include transition(width .6s ease);
}

// Striped bars
//
// `.progress-striped .progress-bar` is deprecated as of v3.2.0 in favor of the
// `.progress-bar-striped` class, which you just add to an existing
// `.progress-bar`.
.progress-striped .progress-bar,
.progress-bar-striped {
  @include gradient-striped;
  background-size: 40px 40px;
}

// Call animation for the active one
//
// `.progress.active .progress-bar` is deprecated as of v3.2.0 in favor of the
// `.progress-bar.active` approach.
.progress.active .progress-bar,
.progress-bar.active {
  @include animation(progress-bar-stripes 2s linear infinite);
}


// Variations
// -------------------------

.progress-bar-success {
  @include progress-bar-variant($progress-bar-success-bg);
}

.progress-bar-info {
  @include progress-bar-variant($progress-bar-info-bg);
}

.progress-bar-warning {
  @include progress-bar-variant($progress-bar-warning-bg);
}

.progress-bar-danger {
  @include progress-bar-variant($progress-bar-danger-bg);
}

// stylelint-disable selector-max-type, selector-no-qualifying-type

.bd-toc {
  font-size: .875rem;
  container-type: inline-size;

  @include media-breakpoint-up(lg) {
    position: sticky;
    top: 5rem;
    right: 0;
    z-index: 2;
    height: subtract(100vh, 7rem);
    overflow-y: auto;
  }

  nav {
    @include font-size(.875rem);

    ul {
      padding-left: 0;
      margin-bottom: 0;
      list-style: none;

      ul {
        padding-left: 1rem;
      }
    }

    a {
      display: block;
      padding: .125rem 0 .125rem .75rem;
      color: inherit;
      text-decoration: none;
      border-left: .125rem solid transparent;

      &:hover,
      &.active {
        color: var(--bd-toc-color);
        border-left-color: var(--bd-toc-color);
      }

      &.active {
        font-weight: 500;
      }

      code {
        font: inherit;
      }
    }
  }
}

.bd-toc-toggle {
  display: flex;
  align-items: center;

  @include media-breakpoint-down(sm) {
    justify-content: space-between;
    width: 100%;
  }

  @include media-breakpoint-down(md) {
    color: var(--bs-body-color);
    border: 1px solid var(--bs-border-color);
    @include border-radius(var(--bs-border-radius));

    &:hover,
    &:focus,
    &:active,
    &[aria-expanded="true"] {
      color: var(--bd-violet);
      background-color: var(--bs-body-bg);
      border-color: var(--bd-violet);
    }

    &:focus,
    &[aria-expanded="true"] {
      box-shadow: 0 0 0 3px rgba(var(--bd-violet-rgb), .25);
    }
  }
}

.bd-toc-collapse {
  @include media-breakpoint-down(md) {
    nav {
      padding: 1.25rem 1.25rem 1.25rem 1rem;
      background-color: var(--bs-tertiary-bg);
      border: 1px solid var(--bs-border-color);
      @include border-radius(var(--bs-border-radius));
    }
  }

  @include media-breakpoint-up(md) {
    display: block !important; // stylelint-disable-line declaration-no-important
  }
}

@use "./add-bar" as *;
@use "../../functions" as *;
@use "../../mixins/helpers" as *;
@use "../../mixins/typography/unstyled-list" as *;
@use "../../mixins/utilities" as *;
@use "../../settings" as *;

$sidenav-level-1-inset: 2;
$sidenav-level-2-inset: 4;
$sidenav-level-3-inset: 6;
$sidenav-level-4-inset: 8;

@mixin nav-list($type) {
  @include unstyled-list();

  @if $type == "sidenav" {
    &__item {
      border-top: units(1px) solid color("base-lighter");
    }
  }

  @if $type == "nav" {
    &-item {
      border-top: units(1px) solid color("base-lighter");
    }
  }

  a:not(.usa-button) {
    display: block;
    padding: units(1) units($sidenav-level-1-inset);
    text-decoration: none;

    &:hover {
      background-color: color("base-lightest");
      text-decoration: none;
    }
  }

  a:not(.usa-button):not(.usa-current) {
    color: color("base-dark");

    &:hover {
      color: color($theme-link-color);
    }

    &:focus {
      outline-offset: 0;
    }
  }

  .usa-current {
    @include add-bar(
      $theme-sidenav-current-border-width,
      "primary",
      "left",
      "pill",
      0.5,
      0.5
    );
    color: color($theme-link-color);
    font-weight: font-weight("bold");

    @include at-media("tablet") {
      @include add-bar(
        $theme-sidenav-current-border-width,
        $theme-link-color,
        "left",
        "pill",
        0,
        0.5
      );
    }
  }
}

@mixin nav-sublist {
  @include unstyled-list();
  margin: 0;

  &-item {
    border-top: units(1px) solid color("base-lighter");
    font-size: font-size($theme-sidenav-font-family, "2xs");
  }

  .usa-current {
    @include remove-bar;

    @include at-media("tablet") {
      @include remove-bar;
    }
  }

  // level 2+
  a:not(.usa-button) {
    padding-left: units($sidenav-level-2-inset);
  }

  // level 3+
  & & a:not(.usa-button) {
    padding-left: units($sidenav-level-3-inset);
  }

  // level 4+
  & & & a:not(.usa-button) {
    padding-left: units($sidenav-level-4-inset);
  }
}

@import "./breadcrumb";
@import "./breadcrumb.md.vars";

// Breadcrumb
// --------------------------------------------------

:host {
  --color: #{$breadcrumb-md-color};
  --color-active: #{$breadcrumb-md-color-active};
  --color-hover: #{$breadcrumb-md-color-active};
  --color-focused: #{$breadcrumb-md-color-focused};
  --background-focused: #{$breadcrumb-md-background-focused};
}

:host(.breadcrumb-active) {
  font-weight: 500;
}

.breadcrumb-native {
  @include padding(6px, 12px, 6px, 12px);
}


// Breadcrumb Separator
// ------------------------------------------

.breadcrumb-separator {
  @include margin($breadcrumb-md-separator-margin-top, $breadcrumb-md-separator-margin-end, $breadcrumb-md-separator-margin-bottom, $breadcrumb-md-separator-margin-start);
}


// Breadcrumb: Focused
// ------------------------------------------

:host(.ion-focused) .breadcrumb-native {
  @include border-radius(4px);

  box-shadow: 0px 1px 2px rgba(0, 0, 0, 0.2), 0px 2px 8px rgba(0, 0, 0, 0.12);
}


// Breadcrumb Separator
// ------------------------------------------

.breadcrumb-separator {
  color: $breadcrumb-md-separator-color;
}


// Breadcrumb Slotted Icons
// ------------------------------------------

::slotted(ion-icon) {
  color: $breadcrumb-md-icon-color;

  font-size: dynamic-font(18px);
}

::slotted(ion-icon[slot="start"]) {
  @include margin(null, 8px, null, null);
}

::slotted(ion-icon[slot="end"]) {
  @include margin(null, null, null, 8px);
}

:host(.breadcrumb-active) ::slotted(ion-icon) {
  color: $breadcrumb-md-icon-color-active;
}


// Breadcrumbs Collapsed Indicator
// --------------------------------------------------

.breadcrumbs-collapsed-indicator {
  @include border-radius(2px);

  background: $breadcrumb-md-indicator-background;

  color: $breadcrumb-md-indicator-color;
}

.breadcrumbs-collapsed-indicator:hover {
  opacity: 0.7;
}

.breadcrumbs-collapsed-indicator:focus {
  background: $breadcrumb-md-indicator-background-focused;
}

@import "./item-divider";
@import "./item-divider.ios.vars";

// iOS Item Divider
// --------------------------------------------------

:host {
  --background: #{$item-divider-ios-background};
  --color: #{$item-divider-ios-color};
  --padding-start: #{$item-divider-ios-padding-start};
  --inner-padding-end: #{$item-divider-ios-padding-end * 0.5};

  @include border-radius(0);

  position: relative;

  min-height: $item-divider-ios-min-height;

  font-size: $item-divider-ios-font-size;

  font-weight: $item-divider-ios-font-weight;
}


// iOS Item Divider Slots
// --------------------------------------------------

:host([slot="start"]) {
  @include margin($item-ios-slot-start-margin-top, $item-ios-slot-start-margin-end, $item-ios-slot-start-margin-bottom, $item-ios-slot-start-margin-start);
}

:host([slot="end"]) {
  @include margin($item-ios-slot-end-margin-top, $item-ios-slot-end-margin-end, $item-ios-slot-end-margin-bottom, $item-ios-slot-end-margin-start);
}

::slotted(ion-icon[slot="start"]),
::slotted(ion-icon[slot="end"]) {
  @include margin($item-ios-icon-slot-margin-top, $item-ios-icon-slot-margin-end, $item-ios-icon-slot-margin-bottom, $item-ios-icon-slot-margin-start);
}


// iOS Item Divider Content
// --------------------------------------------------

::slotted(h1) {
  @include margin(0, 0, 2px);
}

::slotted(h2) {
  @include margin(0, 0, 2px);
}

::slotted(h3),
::slotted(h4),
::slotted(h5),
::slotted(h6) {
  @include margin(0, 0, 3px);
}

::slotted(p) {
  @include margin($item-ios-paragraph-margin-top, $item-ios-paragraph-margin-end, $item-ios-paragraph-margin-bottom, $item-ios-paragraph-margin-start);

  color: $item-ios-paragraph-text-color;

  font-size: $item-ios-paragraph-font-size;

  line-height: normal;

  text-overflow: inherit;

  overflow: inherit;
}

::slotted(h2:last-child)
::slotted(h3:last-child),
::slotted(h4:last-child),
::slotted(h5:last-child),
::slotted(h6:last-child),
::slotted(p:last-child) {
  @include margin(null, null, 0, null);
}

// Icon arrows
.icon-arrow-down,
.icon-arrow-left,
.icon-arrow-right,
.icon-arrow-up,
.icon-downward,
.icon-back,
.icon-forward,
.icon-upward {
  &::before {
    border: $icon-border-width solid currentColor;
    border-bottom: 0;
    border-right: 0;
    height: .65em;
    width: .65em;
  }
}

.icon-arrow-down {
  &::before {
    transform: translate(-50%, -75%) rotate(225deg);
  }
}

.icon-arrow-left {
  &::before {
    transform: translate(-25%, -50%) rotate(-45deg);
  }
}

.icon-arrow-right {
  &::before {
    transform: translate(-75%, -50%) rotate(135deg);
  }
}

.icon-arrow-up {
  &::before {
    transform: translate(-50%, -25%) rotate(45deg);
  }
}

.icon-back,
.icon-forward {
  &::after {
    background: currentColor;
    height: $icon-border-width;
    width: .8em;
  }
}

.icon-downward,
.icon-upward {
  &::after {
    background: currentColor;
    height: .8em;
    width: $icon-border-width;
  }
}

.icon-back {
  &::after {
    left: 55%;
  }
  &::before {
    transform: translate(-50%, -50%) rotate(-45deg);
  }
}

.icon-downward {
  &::after {
    top: 45%;
  }
  &::before {
    transform: translate(-50%, -50%) rotate(-135deg);
  }
}

.icon-forward {
  &::after {
    left: 45%;
  }
  &::before {
    transform: translate(-50%, -50%) rotate(135deg);
  }
}

.icon-upward {
  &::after {
    top: 55%;
  }
  &::before {
    transform: translate(-50%, -50%) rotate(45deg);
  }
}

// Icon caret
.icon-caret {
  &::before {
    border-top: .3em solid currentColor;
    border-right: .3em solid transparent;
    border-left: .3em solid transparent;
    height: 0;
    transform: translate(-50%, -25%);
    width: 0;
  }
}

// Icon menu
.icon-menu {
  &::before {
    background: currentColor;
    box-shadow: 0 -.35em, 0 .35em;
    height: $icon-border-width;
    width: 100%;
  }
}

// Icon apps
.icon-apps {
  &::before {
    background: currentColor;
    box-shadow: -.35em -.35em, -.35em 0, -.35em .35em, 0 -.35em, 0 .35em, .35em -.35em, .35em 0, .35em .35em;
    height: 3px;
    width: 3px;
  }
}

// Sliders
// Credit: https://css-tricks.com/styling-cross-browser-compatible-range-inputs-css/
.slider {
  appearance: none;
  background: transparent;
  display: block;
  width: 100%;
  height: $unit-6;

  &:focus {
    @include control-shadow();
    outline: none;
  }

  &.tooltip:not([data-tooltip]) {
    &::after {
      content: attr(value);
    }
  }

  // Slider Thumb
  &::-webkit-slider-thumb {
    -webkit-appearance: none;
    background: $primary-color;
    border: 0;
    border-radius: 50%;
    height: $unit-3;
    margin-top: -($unit-3 - $unit-h) / 2;
    transition: transform .2s;
    width: $unit-3;
  }
  &::-moz-range-thumb {
    background: $primary-color;
    border: 0;
    border-radius: 50%;
    height: $unit-3;
    transition: transform .2s;
    width: $unit-3;
  }
  &::-ms-thumb {
    background: $primary-color;
    border: 0;
    border-radius: 50%;
    height: $unit-3;
    transition: transform .2s;
    width: $unit-3;
  }

  &:active {
    &::-webkit-slider-thumb {
      transform: scale(1.25);
    }
    &::-moz-range-thumb {
      transform: scale(1.25);
    }
    &::-ms-thumb {
      transform: scale(1.25);
    }
  }

  &:disabled,
  &.disabled {
    &::-webkit-slider-thumb {
      background: $gray-color-light;
      transform: scale(1);
    }
    &::-moz-range-thumb {
      background: $gray-color-light;
      transform: scale(1);
    }
    &::-ms-thumb {
      background: $gray-color-light;
      transform: scale(1);
    }
  }

  // Slider Track
  &::-webkit-slider-runnable-track {
    background: $bg-color-dark;
    border-radius: $border-radius;
    height: $unit-h;
    width: 100%;
  }
  &::-moz-range-track {
    background: $bg-color-dark;
    border-radius: $border-radius;
    height: $unit-h;
    width: 100%;
  }
  &::-ms-track {
    background: $bg-color-dark;
    border-radius: $border-radius;
    height: $unit-h;
    width: 100%;
  }
  &::-ms-fill-lower {
    background: $primary-color;
  }
}
